CREATE OR REPLACE FUNCTION public.get_public_platform_customization() RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$$ DECLARE full_settings jsonb; BEGIN SELECT settings INTO full_settings FROM public.platform_settings WHERE key = 'customization'; IF full_settings IS NULL THEN RETURN jsonb_build_object('pages', '{}'::jsonb); END IF; RETURN jsonb_build_object('pages', COALESCE(full_settings -> 'pages', '{}'::jsonb), 'media', COALESCE(full_settings -> 'media', '{}'::jsonb), 'design', COALESCE(full_settings -> 'design', '{}'::jsonb), 'navigation', COALESCE(full_settings -> 'navigation', '{}'::jsonb)); END; $$$;
